import{_ as o,o as r,c as a,a2 as t}from"./chunks/framework.DYQ4mM3C.js";const f=JSON.parse('{"title":"Profiles","description":"","frontmatter":{},"headers":[],"relativePath":"profiles.md","filePath":"profiles.md","lastUpdated":1782445554000}'),i={name:"profiles.md"};function l(d,e,n,c,s,p){return r(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="profiles" tabindex="-1">Profiles <a class="header-anchor" href="#profiles" aria-label="Permalink to &quot;Profiles&quot;">​</a></h1><p>Profiles are local trusted policy. Repository files may reference a profile with <code>envvault://...</code>, but they cannot change the profile&#39;s target URL, allowlist, credential binding, token lifetime, or project binding.</p><h2 id="kinds" tabindex="-1">Kinds <a class="header-anchor" href="#kinds" aria-label="Permalink to &quot;Kinds&quot;">​</a></h2><p><code>provider-proxy</code> profiles start a localhost proxy during <code>envvault exec</code>. The child process receives a local base URL and local-only bearer token. EnvVault adds the real provider key only when forwarding allowed requests.</p><p><code>inject</code> profiles resolve <code>envvault://&lt;profile&gt;/value</code> to a named credential value. This is the raw injection fallback for tools that cannot use a localhost proxy.</p><h2 id="policy-fields" tabindex="-1">Policy Fields <a class="header-anchor" href="#policy-fields" aria-label="Permalink to &quot;Policy Fields&quot;">​</a></h2><ul><li><code>provider</code>: The proxy provider type. The MVP supports <code>generic</code> and <code>openai-compatible</code>.</li><li><code>credential</code>: The named OS credential store entry used by a provider-proxy or inject profile.</li><li><code>auth_mode</code>: The provider-proxy authentication mode. The MVP supports <code>bearer</code>.</li><li><code>target_url</code>: The fixed provider API base URL the local proxy forwards to.</li><li><code>allowed_paths</code> and <code>allowed_methods</code>: The proxy allowlist enforced before the real provider key is added.</li><li><code>local_token_ttl</code>: The local proxy bearer token lifetime for a child process.</li><li><code>project binding</code>: The local approval tying profile use to a path hash or git remote plus root.</li></ul><h2 id="secret-storage" tabindex="-1">Secret Storage <a class="header-anchor" href="#secret-storage" aria-label="Permalink to &quot;Secret Storage&quot;">​</a></h2><p>Credentials are stored in the OS credential store. Provider-proxy and inject profiles point at named credential values. The config file stores non-secret policy and metadata only.</p><p>EnvVault does not write provider API keys, database URLs, local proxy tokens, or Authorization header values into profile files.</p><h2 id="project-binding" tabindex="-1">Project Binding <a class="header-anchor" href="#project-binding" aria-label="Permalink to &quot;Project Binding&quot;">​</a></h2><p>The default binding mode is <code>git-remote-and-root</code>. First use requires a TTY confirmation that records the approved project identity in user config. Non-interactive use fails closed when the binding is unknown.</p><p>Use <code>none</code> only for low-risk local workflows. Use <code>path-hash</code> when a project has no git remote but still needs local binding.</p>',13)])])}const u=o(i,[["render",l]]);export{f as __pageData,u as default};
